// ── Ordered icon list for the picker ─────────────────────────────────────────

export const LUCIDE_ICON_NAMES: string[] = Object.keys(ICON_DATA);
// Phosphor fill icons (keys are `ph-*`). Referenced as `lucide:ph-crown` etc.
export const PHOSPHOR_ICON_NAMES: string[] = Object.keys(PHOSPHOR_DATA);
// Everything the picker can offer.
export const ALL_ICON_NAMES: string[] = [...LUCIDE_ICON_NAMES, ...PHOSPHOR_ICON_NAMES];

// ── SVG builder ──────────────────────────────────────────────────────────────

function svgElementToString(el: SvgElement): string {
  const [tag, attrs] = el;
  const attrStr = Object.entries(attrs)
    .filter(([k]) => k !== "key")
    .map(([k, v]) => `${k}="${v}"`)
    .join(" ");
  // Self-closing tags (all Lucide elements are self-closing)
  return `<${tag} ${attrStr}/>`;
}

/**
 * Build a complete SVG string for an icon.
 *
 * Two sets: Lucide outline icons (24×24, `stroke`=color) and Phosphor decorative
 * fill icons (`ph-*` keys, 256×256, `fill`=color). Phosphor entries recolor via a
 * single fill, so `strokeWidth` is ignored for them.
 * @param name   icon name (key in ICON_DATA or PHOSPHOR_DATA)
 * @param color  stroke/fill color (default: currentColor)
 * @param strokeWidth  Lucide stroke width (default: 2; ignored for fill icons)
 * @param size   rendered size in px (default: 24)
 */
export function iconToSvg(
  name: string,
  color = "currentColor",
  strokeWidth = 2,
  size = 24,
): string {
  const fill = PHOSPHOR_DATA[name];
  if (fill) {
    const inner = fill.map(svgElementToString).join("");
    return (
      `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" ` +
      `viewBox="0 0 256 256" fill="${color}">${inner}</svg>`
    );
  }
  const node = ICON_DATA[name];
  if (!node) return "";
  const inner = node.map(svgElementToString).join("");
  return (
    `<svg xmlns="http://www.w3.org/2000/svg" width="${size}" height="${size}" ` +
    `viewBox="0 0 24 24" fill="none" stroke="${color}" ` +
    `stroke-width="${strokeWidth}" stroke-linecap="round" stroke-linejoin="round">` +
    `${inner}</svg>`
  );
}

/**
 * Build a data URI for use as an <img> src or Konva Image source.
 */
export function iconToDataUri(
  name: string,
  color = "#FFFFFF",
  strokeWidth = 2,
  size = 24,
): string {
  const svg = iconToSvg(name, color, strokeWidth, size);
  if (!svg) return "";
  return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;
}

/** Check if a layer value is a Lucide icon reference. */
export function isLucideIcon(value: string | undefined): boolean {
  return !!value?.startsWith("lucide:");
}

/** Extract icon name from "lucide:heart" format. */
export function parseLucideIcon(value: string): string {
  return value.slice(7); // strip "lucide:"
}

/** Get raw SVG element data for a given icon name (Lucide or Phosphor). */
export function getIconNode(name: string): SvgElement[] | undefined {
  return ICON_DATA[name] ?? PHOSPHOR_DATA[name];
}
